// ───────────────────────── 純関数（派生ロジック）─────────────────────────

export function vehicleById(id: string): Vehicle | undefined {
  return VEHICLES.find((v) => v.id === id)
}

/** 消耗品の消費率（>1 = 目安超過）。 */
export function serviceFraction(s: ServiceItem): number {
  return s.intervalKm > 0 ? s.sinceKm / s.intervalKm : 1
}

/** 走行距離オーバー（要交換）の項目数。 */
export function overdueServiceCount(v: Vehicle): number {
  return v.services.filter((s) => serviceFraction(s) >= 1).length
}

/** 全期限レコード（車検・点検・保険）を平らに。 */
export function expiryRecords(v: Vehicle): ExpiryRecord[] {
  return [v.shaken, v.teiki, v.jibai, v.ninni]
}

