function formatDate(d: Date): string {
  return `${d.getFullYear()}/${String(d.getMonth() + 1).padStart(2, "0")}/${String(d.getDate()).padStart(2, "0")}`
}

// ─────────────────────────── KPI strip ───────────────────────────

function useKpis() {
  return React.useMemo(() => {
    const total = VEHICLES.length
    const inShop = VEHICLES.filter((v) => v.state === "整備中").length
    const needsWork = VEHICLES.filter((v) => v.state === "要整備").length
    // 車検が30日以内 or 失効
    const shakenSoon = VEHICLES.filter((v) => {
      const { state } = classifyExpiry(v.shaken.due, { today: TODAY })
      return state === "expiring" || state === "expired"
    }).length
    const overdueServices = VEHICLES.reduce((n, v) => n + overdueServiceCount(v), 0)
    return { total, inShop, needsWork, shakenSoon, overdueServices }
  }, [])
}

// ─────────────────────── 要対応キュー (ActionQueue) ───────────────────────

function buildActionItems(onOpen: (id: string) => void): ActionItem[] {
  const items: ActionItem[] = []
  for (const v of VEHICLES) {
    for (const rec of expiryRecords(v)) {
      const { state, days } = classifyExpiry(rec.due, { today: TODAY })
      if (state === "expired") {
        items.push({
          id: `${v.id}-${rec.label}-exp`,
          severity: "critical",
          kind: rec.label === "車検" ? "車検失効" : rec.label.includes("保険") || rec.label.includes("自賠") ? "保険失効" : "点検漏れ",
          title: `${v.carNo}：${rec.label}が失効`,
          detail: `${v.model}・${v.plate}／${rec.label}は運行に必須。即時入庫・更新が必要。`,
          meta: days != null ? `${Math.abs(days)}日超過` : undefined,
          onSelect: () => onOpen(v.id),
        })
      } else if (state === "expiring") {
        items.push({
          id: `${v.id}-${rec.label}-soon`,
          severity: "warning",
          kind: `${rec.label}期限間近`,
          title: `${v.carNo}：${rec.label}の期限が近づいています`,
          detail: `${v.model}・${v.plate}／更新・入庫を計画してください。`,
          meta: days != null ? `残${days}日` : undefined,
          onSelect: () => onOpen(v.id),
        })
      } else if (state === "missing") {
        items.push({
          id: `${v.id}-${rec.label}-missing`,
          severity: "warning",
          kind: "未登録",
          title: `${v.carNo}：${rec.label}が未登録`,
          detail: `${v.model}・${v.plate}／有効期限の登録漏れ。確認してください。`,
          onSelect: () => onOpen(v.id),
        })
      }
    }
    const over = v.services.filter((s) => serviceFraction(s) >= 1)
    if (over.length > 0) {
      items.push({
        id: `${v.id}-svc`,
        severity: over.some((s) => s.note?.includes("要交換")) ? "critical" : "warning",
        kind: "走行距離オーバー",
        title: `${v.carNo}：交換目安を超過（${over.length}件）`,
        detail: `${over.map((s) => s.label).join("・")}／走行距離が交換目安を超えています。`,
        meta: `${formatNumber(v.odometerKm)}km`,
        onSelect: () => onOpen(v.id),
      })
    }
    if (v.defect) {
      items.push({
        id: `${v.id}-defect`,
        severity: v.state === "整備中" ? "info" : "critical",
        kind: v.defect.includes("事故") || v.defect.includes("板金") ? "事故・修理" : "不具合",
        title: `${v.carNo}：${v.defect}`,
        detail: `${v.model}・${v.plate}`,
        onSelect: () => onOpen(v.id),
      })
    }
  }
  return items
}

