        cell: ({ row }) => {
          const tone = STATE_TONE[row.original.state]
          const variant = tone === "success" ? "success" : tone === "warning" ? "warning" : "destructive"
          return <Badge variant={variant}>{row.original.state}</Badge>
        },
      },
      {
        accessorKey: "odometerKm",
        header: "走行距離",
        cell: ({ row }) => (
          <div className="flex flex-col text-right tabular-nums">
            <span className="font-medium">{formatNumber(row.original.odometerKm)} km</span>
            <span className="text-xs text-muted-foreground">月 {formatNumber(row.original.monthlyKm)} km</span>
          </div>
        ),
      },
      {
        id: "shaken",
        header: "次回車検",
        cell: ({ row }) => <ExpiryBadge value={row.original.shaken.due} today={TODAY} showDate formatDate={formatDate} />,
      },
      {
        id: "teiki",
        header: "3ヶ月点検",
        cell: ({ row }) => <ExpiryBadge value={row.original.teiki.due} today={TODAY} showDate={false} formatDate={formatDate} />,
      },
      {
        id: "assignedTo",
        accessorKey: "assignedTo",
        header: "配置",
        cell: ({ row }) => <span className="text-sm text-muted-foreground">{row.original.assignedTo}</span>,
      },
    ],
    []
  )

  return (
    <ActionDataTable<Vehicle, unknown>
      columns={columns}
      data={VEHICLES}
      getRowId={(v) => v.id}
      getRowLabel={(v) => v.carNo}
      enableSelection={false}
      onRowClick={(v) => onOpen(v.id)}
      rowActions={[{ id: "open", label: "詳細", onSelect: (v) => onOpen(v.id) }]}
      filter={{ columnId: "carNo", placeholder: "号車・車種で絞り込み" }}
      pageSize={10}
    />
  )
}

// ─────────────────────── 整備目安メーター ───────────────────────

function ServiceMeter({ s }: { s: ServiceItem }) {
  // 経年（distance な目安が無いもの）は別表示
  if (s.intervalKm <= 1) {
    return (
      <div className="flex items-center justify-between gap-2 text-sm">
        <span className="text-muted-foreground">{s.label}</span>
        <Badge variant={s.note?.includes("劣化") ? "warning" : "secondary"}>{s.note ?? "経年管理"}</Badge>
      </div>
    )
  }
  return (
    <Meter
      label={s.label}
      value={s.sinceKm}
      max={s.intervalKm}
      unit="km"
      formatValue={(n) => `${formatNumber(Math.round(n))}km`}
      thresholds={{ warning: 0.8, over: 1 }}
    />
  )
}

// ─────────────────────── 期限カード ───────────────────────

function ExpiryRow({ rec }: { rec: ExpiryRecord }) {
  return (
    <div className="flex items-center justify-between gap-3 py-1.5">
      <span className="text-sm font-medium text-foreground">{rec.label}</span>
      <ExpiryBadge value={rec.due} today={TODAY} showDate formatDate={formatDate} />
    </div>
  )
}

// ─────────────────────── 車両詳細パネル ───────────────────────

function VehicleDetail({ vehicle }: { vehicle: Vehicle }) {
  // SignedRecord は ID ごとに独立した確定状態を持つ
  const [records, setRecords] = React.useState<Record<string, SignedRecordValue>>({})
  const recordKey = `${vehicle.id}-${vehicle.history[0]?.at ?? "none"}`
  const recordValue: SignedRecordValue = records[recordKey] ?? { status: "draft", addenda: [] }

  const latest = vehicle.history[0]

  return (
    <div className="grid gap-4 lg:grid-cols-[minmax(0,1fr)_320px]">
      <div className="flex flex-col gap-4">
        {/* 整備目安 */}
        <Card>
          <CardHeader>
            <CardTitle as="h3">走行距離による整備目安</CardTitle>
          </CardHeader>
          <CardContent className="flex flex-col gap-3">
            {vehicle.services.map((s) => (
              <ServiceMeter key={s.label} s={s} />
            ))}
          </CardContent>
        </Card>

        {/* 整備記録 + サインオフ */}
        <Card>
          <CardHeader>
            <CardTitle as="h3">整備記録 / 確認</CardTitle>
          </CardHeader>
          <CardContent>
            {latest ? (
              <SignedRecord
                value={recordValue}
                onChange={(v) => setRecords((r) => ({ ...r, [recordKey]: v }))}
                signerId={SIGNER_ID}
              >
                {({ readOnly }) => (
                  <div className="flex flex-col gap-2 rounded-md border border-border bg-muted/30 p-3 text-sm">
                    <div className="flex items-center justify-between">
                      <span className="font-medium text-foreground">{latest.work}</span>
                      <span className="tabular-nums text-xs text-muted-foreground">{latest.at}</span>
                    </div>
                    <MetadataList
                      layout="horizontal"
                      items={[
                        { label: "実施整備士", value: latest.mechanic },
                        { label: "走行距離", value: `${formatNumber(latest.odometerKm)} km` },
                        { label: "対象車両", value: `${vehicle.carNo}・${vehicle.plate}` },
                      ]}
                    />
                    <p className="text-xs text-muted-foreground">
                      {readOnly
                        ? "この記録は確定済みです。修正は追記で行います。"
                        : "内容を確認のうえ「署名・確定」してください。確定後はロックされます。"}
                    </p>
                  </div>
                )}
              </SignedRecord>
            ) : (
              <p className="text-sm text-muted-foreground">整備履歴がありません。</p>
            )}
          </CardContent>
        </Card>
      </div>

      <div className="flex flex-col gap-4">
        {/* 期限 */}
        <Card>
          <CardHeader>
            <CardTitle as="h3">車検・点検・保険の有効期限</CardTitle>
          </CardHeader>
          <CardContent className="flex flex-col divide-y divide-border/60">
            {expiryRecords(vehicle).map((rec) => (
              <ExpiryRow key={rec.label} rec={rec} />
            ))}
          </CardContent>
        </Card>

        {/* 整備履歴 */}
        <Card>
          <CardHeader>
            <CardTitle as="h3">整備履歴</CardTitle>
          </CardHeader>
          <CardContent>
            <Timeline>
              {vehicle.history.map((h, i) => (
                <TimelineItem key={h.at} connector={i < vehicle.history.length - 1}>
                  <TimelineTitle>{h.work}</TimelineTitle>
                  <TimelineTime>{h.at}</TimelineTime>
                  <TimelineDescription>
                    {h.mechanic}・{formatNumber(h.odometerKm)} km
                  </TimelineDescription>
                </TimelineItem>
              ))}
            </Timeline>
          </CardContent>
        </Card>
      </div>
    </div>
  )
}

